-- =============================================
-- Module:      order
-- File:        refund_custom.sql
-- Purpose:     2-stage refund workflow (accept → approve) with rejection/dispute hooks.
-- =============================================

-- Create/Get are auto-generated by pgtempl (CreateDefaultRefund / GetRefund).

-- name: AcceptRefundStage1 :one
UPDATE "order"."refund"
SET "status" = 'Processing',
    "accepted_by_id" = @accepted_by_id,
    "date_accepted" = CURRENT_TIMESTAMP
WHERE "id" = @id AND "status" = 'Pending'
RETURNING *;

-- name: ApproveRefundStage2 :one
UPDATE "order"."refund"
SET "status" = 'Success',
    "approved_by_id" = @approved_by_id,
    "date_approved" = CURRENT_TIMESTAMP,
    "refund_tx_id" = @refund_tx_id
WHERE "id" = @id AND "status" = 'Processing'
RETURNING *;

-- name: RejectRefund :one
UPDATE "order"."refund"
SET "status" = 'Failed',
    "rejection_note" = @rejection_note
WHERE "id" = @id AND "status" IN ('Pending', 'Processing')
RETURNING *;

-- name: HasActiveRefundForOrder :one
SELECT EXISTS (
    SELECT 1 FROM "order"."refund"
    WHERE "order_id" = @order_id
      AND "status" IN ('Pending', 'Processing')
) AS has_active;

-- GetRefundSnapshotByOrder is the per-iteration projection PayoutWorkflow
-- reads while watching escrow. has_active_refund flips while any refund is
-- being negotiated; last_refund_approved becomes true once the most recent
-- refund row for this order has settled in Success.
-- name: GetRefundSnapshotByOrder :one
WITH all_refunds AS (
    SELECT "status", "date_created"
    FROM "order"."refund"
    WHERE "order_id" = @order_id
)
SELECT
    EXISTS (
        SELECT 1 FROM all_refunds
        WHERE "status" IN ('Pending', 'Processing')
    )::BOOLEAN AS has_active_refund,
    COALESCE(
        (SELECT "status" FROM all_refunds ORDER BY "date_created" DESC LIMIT 1) = 'Success'::"order"."status",
        false
    )::BOOLEAN AS last_refund_approved;

-- name: ListBuyerRefunds :many
SELECT * FROM "order"."refund"
WHERE "account_id" = @account_id
ORDER BY "date_created" DESC
LIMIT @limit_count::INTEGER OFFSET @offset_count::INTEGER;

-- name: ListSellerRefunds :many
SELECT r.* FROM "order"."refund" r
JOIN "order"."order" o ON o."id" = r."order_id"
WHERE o."seller_id" = @seller_id
ORDER BY r."date_created" DESC
LIMIT @limit_count::INTEGER OFFSET @offset_count::INTEGER;
